const destX = args.destination.x;
const destZ = args.destination.z;
const movements = new Movements(bot);
bot.pathfinder.setMovements(movements);
const goal = new goals.GoalXZ(destX, destZ);

let eaten = 0;

const movePromise = bot.pathfinder.goto(goal).catch(() => {});

while (bot.food < 20) {
  const bread = bot.inventory.items().find(item => item.name === 'bread');
  if (!bread) break;
  try {
    await bot.equip(bread, 'hand');
    await bot.consume();
    eaten++;
  } catch (err) {
    await new Promise(resolve => setTimeout(resolve, 100));
  }
}

try {
  await movePromise;
} catch (err) {}

bot.pathfinder.setGoal(null);

let result = `<RETREATED>: Moved toward (${destX}, ${destZ}).`;
if (eaten > 0) {
  result += ` Ate ${eaten} bread.`;
} else if (!bot.inventory.items().find(item => item.name === 'bread')) {
  result += ` No bread available.`;
} else {
  result += ` Hunger already full or could not eat.`;
}
result += ` Final hunger: ${bot.food}.`;
return result;
